#include "qp/labels/label.hpp"
#include "qp/schema/validation.hpp"
namespace qp::labels { Result<void> validate(const LabelValue& v){ if(v.symbol.empty()) return Err(Error{ErrorCode::InvalidData,"label symbol empty"}); auto ok=schema::validate_non_empty(v.name,"label.name"); if(!ok) return ok; ok=schema::validate_time_interval(v.label_start_ts,v.label_end_ts); if(!ok) return ok; if(v.label_start_ts <= v.sample_ts) return Err(Error{ErrorCode::LeakageDetected,"label must start strictly after sample timestamp"}); if(v.kind!=LabelKind::Regression && v.kind!=LabelKind::BinaryClassification && v.kind!=LabelKind::MultiClassClassification) return Err(Error{ErrorCode::InvalidData,"invalid label kind"}); if(!v.leakage_safe) return Err(Error{ErrorCode::LeakageDetected,"label marked leakage unsafe"}); return schema::validate_finite(v.value,"label.value"); } }
